-- ═══════════════════════════════════════
-- OFF MARKET — AUTO-GENERATION DE CONTRATS
-- ═══════════════════════════════════════
-- Ajoute les types de notifications pour les contrats
-- et insere le template de contrat par defaut.

-- Mettre a jour la contrainte de type sur notifications
-- pour inclure contract_signed, contract_generated et onboarding_complete
ALTER TABLE public.notifications DROP CONSTRAINT IF EXISTS notifications_type_check;
ALTER TABLE public.notifications ADD CONSTRAINT notifications_type_check CHECK (
  type = ANY (ARRAY[
    'new_message', 'mention', 'form_response', 'module_complete',
    'task_assigned', 'task_due', 'student_inactive', 'new_enrollment',
    'ai_insight', 'system', 'feed', 'contract_signed', 'contract_generated',
    'onboarding_complete'
  ])
);

-- Inserer le template de contrat par defaut (si aucun n'existe)
INSERT INTO public.contract_templates (title, content, variables)
SELECT
  'Contrat d''accompagnement Off-Market',
  E'CONTRAT D''ACCOMPAGNEMENT OFF-MARKET\n═══════════════════════════════════════\n\nEntre les soussignes :\n\n1. ALEXIA LANEAU, operant sous la marque Off-Market\n   Siege social : Paris, France\n   SIRET : En cours d''immatriculation\n   Ci-apres denommee \"Le Prestataire\"\n\n2. {{client_name}}\n   Email : {{client_email}}\n   Ci-apres denomme(e) \"Le Client\"\n\nIl a ete convenu ce qui suit :\n\n\n─── ARTICLE 1 : OBJET DU CONTRAT ────────────────────────\n\nLe present contrat a pour objet de definir les conditions dans lesquelles le Prestataire s''engage a fournir au Client un accompagnement personnalise en coaching business, incluant :\n\n  • Un suivi individuel avec un coach dedie (CSM)\n  • L''acces a la plateforme Off-Market et ses outils\n  • L''acces aux formations et ressources en ligne\n  • La participation aux sessions de groupe et lives\n  • Un plan d''action personnalise et suivi des objectifs\n\n\n─── ARTICLE 2 : DUREE ───────────────────────────────────\n\nLe present contrat est conclu pour une duree de {{duree}}, a compter de la date de signature.\n\nA l''issue de cette periode, le contrat pourra etre renouvele par accord mutuel des parties.\n\n\n─── ARTICLE 3 : TARIF ET MODALITES DE PAIEMENT ─────────\n\nLe montant total de l''accompagnement est fixe a {{montant}} TTC.\n\nLe paiement peut etre effectue :\n  • En une seule fois a la signature du contrat\n  • En plusieurs echeances mensuelles selon l''echeancier convenu\n\nTout retard de paiement entrainera l''application d''une penalite de retard calculee au taux legal en vigueur.\n\n\n─── ARTICLE 4 : OBLIGATIONS DU PRESTATAIRE ─────────────\n\nLe Prestataire s''engage a :\n  • Mettre a disposition les outils et ressources de la plateforme\n  • Assurer un suivi regulier via le coach dedie\n  • Organiser des sessions de groupe selon le calendrier prevu\n  • Adapter l''accompagnement aux besoins specifiques du Client\n  • Respecter la confidentialite des informations partagees\n\n\n─── ARTICLE 5 : OBLIGATIONS DU CLIENT ──────────────────\n\nLe Client s''engage a :\n  • Participer activement aux sessions et utiliser les outils mis a disposition\n  • Effectuer les paiements selon les modalites convenues\n  • Respecter les regles de la communaute Off-Market\n  • Ne pas partager les contenus et ressources avec des tiers\n\n\n─── ARTICLE 6 : RESILIATION ─────────────────────────────\n\nChaque partie peut resilier le contrat avec un preavis de 14 jours par ecrit.\n\nEn cas de resiliation par le Client avant le terme :\n  • Les sommes deja versees restent acquises au Prestataire\n  • Les echeances restantes demeurent dues sauf accord contraire\n\nEn cas de manquement grave de l''une des parties a ses obligations, l''autre partie pourra resilier le contrat de plein droit apres mise en demeure restee sans effet pendant 15 jours.\n\n\n─── ARTICLE 7 : CONFIDENTIALITE ─────────────────────────\n\nLes parties s''engagent a maintenir la confidentialite de toutes les informations echangees dans le cadre du present contrat.\n\nCette obligation de confidentialite survivra a la fin du contrat pour une duree de 2 ans.\n\n\n─── ARTICLE 8 : PROPRIETE INTELLECTUELLE ───────────────\n\nL''ensemble des contenus, methodes et outils mis a disposition sur la plateforme Off-Market restent la propriete exclusive du Prestataire.\n\nLe Client beneficie d''un droit d''utilisation personnel et non-cessible pendant la duree du contrat.\n\n\n─── ARTICLE 9 : LIMITATION DE RESPONSABILITE ───────────\n\nLe Prestataire s''engage a fournir ses meilleurs efforts dans l''accompagnement du Client. Toutefois, les resultats dependent de l''implication personnelle du Client et ne sauraient etre garantis.\n\nLa responsabilite du Prestataire est limitee au montant total du contrat.\n\n\n─── ARTICLE 10 : DROIT APPLICABLE ──────────────────────\n\nLe present contrat est soumis au droit francais.\n\nTout litige relatif a son interpretation ou son execution sera soumis aux tribunaux competents de Paris.\n\n\n─── SIGNATURES ──────────────────────────────────────────\n\nFait en deux exemplaires numeriques, le {{date}}.\n\nPour le Prestataire :                    Pour le Client :\nAlexia Laneau                            {{client_name}}\nOff-Market                               ',
  '[{"key": "client_name", "label": "Nom du client", "type": "text"}, {"key": "client_email", "label": "Email du client", "type": "email"}, {"key": "date", "label": "Date", "type": "date"}, {"key": "montant", "label": "Montant", "type": "text", "defaultValue": "4 000 EUR"}, {"key": "duree", "label": "Duree", "type": "text", "defaultValue": "4 mois"}]'::jsonb
WHERE NOT EXISTS (
  SELECT 1 FROM public.contract_templates WHERE is_active = true
);
